    "inlineSchema": "// Open-Source OCPP CMS - Prisma Schema\n// Clean, production-ready schema for OCPP 1.6 Charge Point Management System\n\ngenerator client {\n  provider = \"prisma-client\"\n  output   = \"../src/generated/prisma\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\n// Admin user accounts\nmodel User {\n  id        Int      @id @default(autoincrement())\n  email     String   @unique\n  password  String\n  role      String   @default(\"admin\")\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  chargingStations ChargingStation[]\n  chargers         Charger[]\n  rfidUsers        RfidUser[]\n}\n\n// Charging station / Site location\nmodel ChargingStation {\n  id                      Int      @id @default(autoincrement())\n  station_name            String\n  street_name             String\n  state                   String\n  city                    String\n  postal_code             String\n  latitude                Float\n  longitude               Float\n  on_site_person_name     String\n  on_site_contact_details String\n  emergency_contact       String\n  status                  String   @default(\"active\")\n  owner_id                Int\n  createdAt               DateTime @default(now())\n  updatedAt               DateTime @updatedAt\n\n  owner    User      @relation(fields: [owner_id], references: [id])\n  chargers Charger[]\n}\n\n// Charging Point / Charger\nmodel Charger {\n  charger_id          Int      @id @default(autoincrement())\n  model               String\n  name                String   @unique\n  manufacturer        String\n  serial_number       String   @unique\n  manufacturing_date  DateTime\n  power_capacity      Float\n  power_consumption   Float\n  status              String   @default(\"offline\")\n  last_heartbeat      DateTime @default(\"1970-01-01T00:00:00.000Z\")\n  firmware_version    String\n  warranty_period     String\n  service_contacts    String\n  latitude            Float?\n  longitude           Float?\n  owner_id            Int\n  charging_station_id Int\n  createdAt           DateTime @default(now())\n  updatedAt           DateTime @updatedAt\n\n  owner           User            @relation(fields: [owner_id], references: [id])\n  chargingStation ChargingStation @relation(fields: [charging_station_id], references: [id])\n  connectors      Connector[]\n  transactions    Transaction[]\n  ocppLogs        OcppLog[]\n  rfidSessions    RfidSession[]\n  tariffs         Tariff[]\n}\n\n// Charge connector (multiple per charger)\nmodel Connector {\n  connector_id   Int      @id @default(autoincrement())\n  connector_name String   @default(\"Connector 1\")\n  status         String\n  current_type   String\n  max_current    Float?\n  max_power      Float?\n  mac_address    String?\n  charger_id     Int\n  createdAt      DateTime @default(now())\n  updatedAt      DateTime @updatedAt\n\n  charger Charger @relation(fields: [charger_id], references: [charger_id])\n}\n\n// RFID tag whitelist\nmodel RfidUser {\n  rfid_user_id Int      @id @default(autoincrement())\n  rfid_tag     String   @unique\n  name         String\n  email        String?\n  phone        String?\n  company_name String?\n  address      String?\n  type         String   @default(\"postpaid\")\n  active       Boolean  @default(true)\n  owner_id     Int\n  createdAt    DateTime @default(now())\n  updatedAt    DateTime @updatedAt\n\n  owner        User          @relation(fields: [owner_id], references: [id])\n  rfidSessions RfidSession[]\n}\n\n// RFID post-paid charging sessions\nmodel RfidSession {\n  id                Int       @id @default(autoincrement())\n  transactionId     Int       @unique\n  rfidUserId        Int\n  charger_id        Int\n  connectorName     String\n  charger           Charger   @relation(fields: [charger_id], references: [charger_id])\n  startTime         DateTime  @default(now())\n  endTime           DateTime?\n  initialMeterValue Float?\n  finalMeterValue   Float?\n  energyConsumed    Float     @default(0)\n  tariffRate        Float?\n  amountDue         Float     @default(0)\n  status            String    @default(\"charging\")\n  createdAt         DateTime  @default(now())\n  updatedAt         DateTime  @updatedAt\n\n  rfidUser RfidUser @relation(fields: [rfidUserId], references: [rfid_user_id])\n}\n\n// Simplified transaction tracking\nmodel Transaction {\n  id                Int       @id @default(autoincrement())\n  transactionId     Int\n  connectorName     String\n  charger_id        Int\n  charger           Charger   @relation(fields: [charger_id], references: [charger_id])\n  startTime         DateTime  @default(now())\n  endTime           DateTime?\n  initialMeterValue Float?\n  finalMeterValue   Float?\n  energyConsumed    Float     @default(0)\n  status            String    @default(\"initiated\")\n  idTag             String?\n  createdAt         DateTime  @default(now())\n  updatedAt         DateTime  @updatedAt\n}\n\n// OCPP message logging for debugging\nmodel OcppLog {\n  id            Int      @id @default(autoincrement())\n  chargerId     Int\n  charger       Charger  @relation(fields: [chargerId], references: [charger_id])\n  transactionId Int?\n  timestamp     DateTime @default(now())\n  direction     String\n  message       String\n}\n\n// Optional: Tariff for pricing\nmodel Tariff {\n  tariff_id        Int      @id @default(autoincrement())\n  tariff_name      String   @unique\n  charge           Float\n  electricity_rate Float\n  createdAt        DateTime @default(now())\n  updatedAt        DateTime @updatedAt\n\n  chargers Charger[]\n}\n",
